import{_ as o,o as t,c as a,a3 as r}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Namespace clore::net::anthropic::protocol","description":"clore::net::anthropic::protocol 命名空间负责实现与 Anthropic 消息 API 交互所需的协议层功能。它封装了请求和响应的序列化与反序列化逻辑，提供了一系列用于构建请求 URL、生成 JSON 请求体、解析响应文本及工具参数、追加工具输出结果的核心函数（如 build_messages_url、build_request_json、parse_response、parse_response_text、parse_tool_arguments、append_tool_outputs）。此外，该命名空间还声明了协议相关的常量与数据模型变量（如 stop_reason_value、model_value、tool_choice、tools 等），用于统一管理协议字段的取值和结构。","frontmatter":{"title":"Namespace clore::net::anthropic::protocol","description":"clore::net::anthropic::protocol 命名空间负责实现与 Anthropic 消息 API 交互所需的协议层功能。它封装了请求和响应的序列化与反序列化逻辑，提供了一系列用于构建请求 URL、生成 JSON 请求体、解析响应文本及工具参数、追加工具输出结果的核心函数（如 build_messages_url、build_request_json、parse_response、parse_response_text、parse_tool_arguments、append_tool_outputs）。此外，该命名空间还声明了协议相关的常量与数据模型变量（如 stop_reason_value、model_value、tool_choice、tools 等），用于统一管理协议字段的取值和结构。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/anthropic/protocol/index.md","filePath":"zh/clore/namespaces/clore/net/anthropic/protocol/index.md"}'),c={name:"zh/clore/namespaces/clore/net/anthropic/protocol/index.md"};function n(p,e,l,s,i,d){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="namespace-clore-net-anthropic-protocol" tabindex="-1">Namespace <code>clore::net::anthropic::protocol</code> <a class="header-anchor" href="#namespace-clore-net-anthropic-protocol" aria-label="Permalink to &quot;Namespace `clore::net::anthropic::protocol`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>clore::net::anthropic::protocol</code> 命名空间负责实现与 Anthropic 消息 API 交互所需的协议层功能。它封装了请求和响应的序列化与反序列化逻辑，提供了一系列用于构建请求 URL、生成 JSON 请求体、解析响应文本及工具参数、追加工具输出结果的核心函数（如 <code>build_messages_url</code>、<code>build_request_json</code>、<code>parse_response</code>、<code>parse_response_text</code>、<code>parse_tool_arguments</code>、<code>append_tool_outputs</code>）。此外，该命名空间还声明了协议相关的常量与数据模型变量（如 <code>stop_reason_value</code>、<code>model_value</code>、<code>tool_choice</code>、<code>tools</code> 等），用于统一管理协议字段的取值和结构。</p><p>在整体架构中，<code>clore::net::anthropic::protocol</code> 扮演着适配层的角色，位于底层网络通信和上层业务逻辑之间。它将原始的网络响应字符串转换为结构化的整数句柄或状态码，供上层模块（如 <code>clore::net::anthropic::detail::Protocol</code>）进一步使用，从而解耦了协议细节与应用逻辑。调用者通过该命名空间提供的函数即可完成与 Anthropic 协议相关的核心操作，而无需直接处理 JSON 或 HTTP 细节。</p><h2 id="subnamespaces" tabindex="-1">Subnamespaces <a class="header-anchor" href="#subnamespaces" aria-label="Permalink to &quot;Subnamespaces&quot;">​</a></h2><ul><li><a href="./detail/"><code>clore::net::anthropic::protocol::detail</code></a></li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-anthropic-protocol-append-tool-outputs" tabindex="-1"><code>clore::net::anthropic::protocol::append_tool_outputs</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-append-tool-outputs" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::append_tool_outputs`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:209</code></p><p>Definition: <code>network/anthropic.cppm:628</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>函数 <code>clore::net::anthropic::protocol::append_tool_outputs</code> 用于将工具调用的输出结果追加到当前正在构造的协议消息中。它接收工具输出的必要数据，并按照 Anthropic 协议格式将其集成到消息结构中。调用者应当在构建需要包含工具结果的请求时调用此函数，确保所有工具输出在发送前被正确附加。该函数的返回值指示操作是否成功，通常为 <code>int</code> 类型的状态码。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>将工具输出合并到消息历史中</li><li>在 Anthropic 协议处理中作为工具结果处理的封装</li></ul><h3 id="clore-net-anthropic-protocol-build-messages-url" tabindex="-1"><code>clore::net::anthropic::protocol::build_messages_url</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-build-messages-url" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::build_messages_url`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:201</code></p><p>Definition: <code>network/anthropic.cppm:224</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>Declaration: <a href="./functions/build-messages-url">Declaration</a></p><p>函数 <code>clore::net::anthropic::protocol::build_messages_url</code> 接受一个 <code>std::string_view</code> 参数并返回一个 <code>std::string</code> 表示的 URL。此函数负责根据提供的输入构造指向 Anthropic 消息 API 的完整端点地址。调用者必须确保传入有效的参数（例如资源标识符或请求上下文），以生成正确的 URL。生成的 URL 供上层组件（如 <code>clore::net::anthropic::detail::Protocol::build_url</code>）进一步使用。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>clore::net::anthropic::detail::Protocol::build_url</code> to produce the messages endpoint URL</li></ul><h3 id="clore-net-anthropic-protocol-build-request-json" tabindex="-1"><code>clore::net::anthropic::protocol::build_request_json</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-build-request-json" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::build_request_json`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:203</code></p><p>Definition: <code>network/anthropic.cppm:235</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>clore::net::anthropic::protocol::build_request_json</code> 接受一个 <code>const int &amp;</code> 参数，返回一个 <code>int</code> 值。调用者应提供一个有效的整数引用，该函数将依据该引用构建对应的请求 JSON 并返回一个表示操作结果的整数。函数不直接修改传入的参数，调用方负责保证参数在调用期间有效。</p><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called to create the JSON payload for an Anthropic messages API request</li><li>Typically used before sending the HTTP request</li></ul><h3 id="clore-net-anthropic-protocol-parse-response" tabindex="-1"><code>clore::net::anthropic::protocol::parse_response</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-parse-response" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::parse_response`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:205</code></p><p>Definition: <code>network/anthropic.cppm:460</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>函数 <code>clore::net::anthropic::protocol::parse_response</code> 接受一个 <code>std::string_view</code> 形式的原始响应数据，并将其解析为一个整数结果。调用者应提供有效且完整的响应内容。该函数返回的整数值代表解析后的状态或提取的数值，具体含义由协议定义的行为确定，调用者须依据该返回值进行后续流程的决策。</p><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Parsing raw JSON response from Anthropic API</li><li>Extracting <code>CompletionResponse</code> from the JSON payload</li><li>Error handling for malformed or error responses</li></ul><h3 id="clore-net-anthropic-protocol-parse-response-text" tabindex="-1"><code>clore::net::anthropic::protocol::parse_response_text</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-parse-response-text" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::parse_response_text`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:215</code></p><p>Definition: <code>network/anthropic.cppm:636</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>clore::net::anthropic::protocol::parse_response_text</code> 是一个模板函数，负责从给定的响应对象中提取文本内容。它接受一个 <code>const</code> 引用参数（类型由模板参数 <code>T</code> 决定），并返回一个表示解析后文本的 <code>int</code> 值。该函数为调用者提供了与具体响应表示无关的文本获取接口，其行为假设传入的响应对象已按协议格式正确构建。</p><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by callers needing to parse the text content of an Anthropic API completion response into a specific type.</li></ul><h3 id="clore-net-anthropic-protocol-parse-tool-arguments" tabindex="-1"><code>clore::net::anthropic::protocol::parse_tool_arguments</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-parse-tool-arguments" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::parse_tool_arguments`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:218</code></p><p>Definition: <code>network/anthropic.cppm:641</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>parse_tool_arguments</code> 是一个模板函数，它接受一个类型为 <code>const int &amp;</code> 的参数并返回 <code>int</code>。调用者负责传入一个有效的整数引用，该引用通常来自诸如 <code>parse_response</code> 或其他解析函数的输出，表示已解析的响应数据。该函数解析并提取工具参数，返回一个整数句柄，供后续如 <code>append_tool_outputs</code> 等函数使用。返回的句柄必须与整个工具调用生命周期一致，调用者应确保在不再需要时释放或重置该句柄。</p><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>used to extract typed arguments from an Anthropic tool call</li></ul><h3 id="clore-net-anthropic-protocol-text-from-response" tabindex="-1"><code>clore::net::anthropic::protocol::text_from_response</code> <a class="header-anchor" href="#clore-net-anthropic-protocol-text-from-response" aria-label="Permalink to &quot;`clore::net::anthropic::protocol::text_from_response`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:207</code></p><p>Definition: <code>network/anthropic.cppm:623</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>clore::net::anthropic::protocol::text_from_response</code> 接受一个响应对象（<code>const int &amp;</code>）并返回一个整数形式的文本数据。调用者负责提供有效的响应，此函数假定响应已按照协议格式正确构造。返回的整数代表从响应中提取的文本内容。</p><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Extracting text from a <code>CompletionResponse</code></li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net::anthropic</a></li><li><a href="./detail/">Namespace clore::net::anthropic::protocol::detail</a></li></ul>',59)])])}const m=o(c,[["render",n]]);export{u as __pageData,m as default};
